  ('dietitian-moex-06930', 'dietitian', 'dietitian-moex-103-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列何者正確？①營養調查獲得的個人營養素攝取量 ②國人膳食營養素建議參考攝取量中的 RDA', '["健康人的營養素平均需要量", "應高於", "", "應低於"]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "88bfbf70e93a", "answer_pdf_sha1": "6c30510e24d9", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-06931', 'dietitian', 'dietitian-moex-103-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '關於食物平衡表（food balance sheet）之敘述，下列何者錯誤？ 可計算國人平均實際食物攝取量 我國每年由行政院農業委員會編製 常用來進行國際間飲食與罹患疾病相關性研究 提供一國的飲食趨勢資料，但依每個國家之發展程度，統計資料的準確度可能有差異', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "88bfbf70e93a", "answer_pdf_sha1": "6c30510e24d9", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-06932', 'dietitian', 'dietitian-moex-103-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '關於頭圍的敘述，下列何者錯誤？ 嬰幼兒頭圍的大小與腦部發育是否正常有關 嬰幼兒頭圍的大小與營養狀況密切相關 嬰兒出生12個月內，頭圍增加最快速 幼兒滿3歲後，頭圍的增加趨緩', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "88bfbf70e93a", "answer_pdf_sha1": "6c30510e24d9", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-06933', 'dietitian', 'dietitian-moex-103-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '問卷題目的編排原則，下列敘述何者錯誤？ 開放式問題放在封閉式問題後面 題目應有適當的間隔，以免版面編排過於擁擠 題目可依據邏輯順序呈現，以利受試者思考及回答 受試者的基本資料如年齡、教育程度等問題，應放在問卷的前面詢問', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "88bfbf70e93a", "answer_pdf_sha1": "6c30510e24d9", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
